<template><div><div class="page-title">工单管理</div><div class="page-card"><div class="toolbar"><el-input v-model="query.title" placeholder="工单标题" clearable style="width:180px"/><el-select v-model="query.status" placeholder="状态" clearable style="width:150px"><el-option label="待派单" :value="1"/><el-option label="待接单" :value="2"/><el-option label="处理中" :value="3"/><el-option label="已完成" :value="4"/><el-option label="已取消" :value="5"/></el-select><el-button type="primary" @click="loadData">查询</el-button><el-button @click="reset">重置</el-button><el-button type="success" @click="openCreate">创建工单</el-button></div><el-table :data="records" v-loading="loading" border><el-table-column prop="id" label="ID" width="70"/><el-table-column prop="orderNo" label="工单编号" min-width="180"/><el-table-column prop="title" label="标题" min-width="160"/><el-table-column prop="faultType" label="故障类型" width="120"/><el-table-column prop="faultLocation" label="位置" min-width="160"/><el-table-column prop="priority" label="优先级" width="90"/><el-table-column label="状态" width="110"><template #default="{row}"><el-tag>{{ workOrderStatusText(row.status) }}</el-tag></template></el-table-column><el-table-column label="操作" width="280" fixed="right"><template #default="{row}"><el-button size="small" @click="viewDetail(row)">详情</el-button><el-button size="small" type="primary" @click="autoAssign(row)">自动派单</el-button><el-button size="small" type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table><el-pagination style="margin-top:16px" background layout="total, prev, pager, next, sizes" :total="total" v-model:current-page="query.pageNo" v-model:page-size="query.pageSize" @current-change="loadData" @size-change="loadData"/></div><el-dialog v-model="createVisible" title="创建工单" width="600px"><el-form :model="form" label-width="100px"><el-form-item label="设备ID"><el-input-number v-model="form.deviceId" :min="1"/></el-form-item><el-form-item label="标题"><el-input v-model="form.title"/></el-form-item><el-form-item label="描述"><el-input v-model="form.description" type="textarea"/></el-form-item><el-form-item label="故障类型"><el-input v-model="form.faultType"/></el-form-item><el-form-item label="故障位置"><el-input v-model="form.faultLocation"/></el-form-item><el-form-item label="联系电话"><el-input v-model="form.contactPhone"/></el-form-item><el-form-item label="优先级"><el-input-number v-model="form.priority" :min="1" :max="5"/></el-form-item></el-form><template #footer><el-button @click="createVisible=false">取消</el-button><el-button type="primary" @click="saveCreate">提交</el-button></template></el-dialog><el-dialog v-model="detailVisible" title="工单详情" width="720px"><pre class="detail-json">{{ JSON.stringify(detail,null,2) }}</pre></el-dialog></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage,ElMessageBox } from 'element-plus';import { pageWorkOrders,createWorkOrder,deleteWorkOrder,getWorkOrderDetail,autoAssignWorkOrder } from '../api/workorder';const loading=ref(false),records=ref([]),total=ref(0),detail=ref(null),detailVisible=ref(false),createVisible=ref(false);const query=reactive({pageNo:1,pageSize:10,title:'',status:undefined});const form=reactive({deviceId:1,title:'',description:'',faultType:'',faultLocation:'',contactPhone:'',priority:3});async function loadData(){loading.value=true;try{const data=await pageWorkOrders(query);records.value=data?.records||[];total.value=data?.total||0}finally{loading.value=false}}function reset(){query.pageNo=1;query.title='';query.status=undefined;loadData()}function openCreate(){Object.assign(form,{deviceId:1,title:'',description:'',faultType:'',faultLocation:'',contactPhone:'',priority:3});createVisible.value=true}async function saveCreate(){await createWorkOrder(form);ElMessage.success('创建成功');createVisible.value=false;loadData()}async function viewDetail(row){detail.value=await getWorkOrderDetail(row.id);detailVisible.value=true}async function autoAssign(row){await autoAssignWorkOrder(row.id);ElMessage.success('自动派单成功');loadData()}async function remove(row){await ElMessageBox.confirm(`确认删除工单 ${row.title}？`,'提示',{type:'warning'});await deleteWorkOrder(row.id);ElMessage.success('删除成功');loadData()}function workOrderStatusText(s){return {1:'待派单',2:'待接单',3:'处理中',4:'已完成',5:'已取消'}[Number(s)]||s}onMounted(loadData)</script><style scoped>.detail-json{background:#0f172a;color:#dbeafe;padding:16px;border-radius:12px;max-height:520px;overflow:auto}</style>
